scwin.onpageload = function () {
  console.log("PGM : 표준원가실적비교표 (co_404_01_13b)");
  const codeOptions = [{
    grpCd: "CO012",
    compID: "lc_unit"
  } // 단위               
  ];
  $c.data.setCommonCode($p, codeOptions);
  ed_srchCloseYm.setValue(scwin.fromDate_YyMm);
  scwin.f_CloseYm();
};

