//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function () {
  scwin.f_SetDefaultUnit();
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit = function () {
  var rcnt = dlt_commonCodeCO012.getRowCount();
  if (rcnt < 1) return;
  var index = 0;
  for (i = 0; i < rcnt; i++) {
    if (dlt_commonCodeCO012.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
      index = i;
      break;
    }
  }
  lc_unit.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 마지막 마감년월를 구한다.
//-------------------------------------------------------------------------	
scwin.f_CloseYm = function () {
  console.log("f_CloseYm");
  dma_closeYm.set("sysCd", "ManagementProfitAndLossEBC");
  dma_closeYm.set("queryId", "retrieveManagementProfitAndLossCloseYm");
  dma_closeYm.set("param3", "000");
  $c.sbm.execute($p, sbm_closeYm);
};

//-------------------------------------------------------------------------
// 버전정보를 구한다.  -> 공통함수 적용
//-------------------------------------------------------------------------
scwin.f_GetVersion = function () {
  console.log("f_GetVersion");
  dma_version.set("sysCd", "CommonEBC");
  dma_version.set("queryId", "retrieveVersionInfo");
  dma_version.set("param1", ed_srchCloseYm.getValue().trim().substr(0, 4) + "00");
  $c.sbm.execute($p, sbm_version);
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
  if (ds_version.getRowCount() < 1) return;
  var index = 0;
  for (i = 0; i <= ds_version.getRowCount(); i++) {
    if (ds_version.getCellData(i, "col3") == DGlobalValue.TRUE) {
      index = i;
      break;
    }
  }
  lc_version.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_search, [ed_srchCloseYm, lc_version]);
  ed_acctDeptCd.setValue("");
  ed_acctDeptNm.setValue("");
};

//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function (inObj, inObjNm) {
  let inValue1 = $c.gus.cfGetValue($p, inObj);
  let inValue2 = $c.gus.cfGetValue($p, inObjNm);
  if ($c.gus.cfIsNull($p, inValue1) && $c.gus.cfIsNull($p, inValue2)) {
    for (var i = 1; i < scwin.f_IsPopUp.arguments.length; i++) {
      $c.gus.cfSetValue($p, scwin.f_IsPopUp.arguments[i], "");
    }
    return false;
  }
  return true;
};

//-------------------------------------------------------------------------
// 부서코드팝업 acctDeptCd
//-------------------------------------------------------------------------
scwin.f_acctDeptCdPopUp = function () {
  var pW = ",,,0,";
  udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(), "T" // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
  , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
  , null // Title순서
  , null // 보여주는 각 컬럼들의 폭
  , null // 컬럼중에서 숨기는 컬럼 지정
  , pW // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
  , "450" // POP-UP뛰을때 원도우의 사용자 정의 폭
  , "500" // POP-UP뛰을때 윈도우의 사용자 정의 높이
  , null // 윈도우 위치 Y좌표
  , null // 윈도우 위치 X좌표
  , null // 중복체크여부	("F")
  , "F" // 전체검색허용여부	("F")
  , null // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
  );
};
scwin.udc_acctDeptCd_callBackFunc = function (ret) {
  console.log("udc_acctDeptCd_callBackFunc");
  console.log(ret);
  if (ret[0] != "N/A" && !$c.gus.cfIsNull($p, ret)) {
    ed_acctDeptCd.setValue(ret[0]);
    ed_acctDeptNm.setValue(ret[1]);
  } else {
    ed_acctDeptCd.setValue("");
    ed_acctDeptNm.setValue("");
  }
};

