//-------------------------------------------							
// 그리드 높이 늘리고 줄이기							
//-------------------------------------------							
scwin.f_grdHeiht = function (gridNm, size) {
  let strHeight = gridNm.style.height;
  let intHeight = parseInt(strHeight.replace("px", ""));
  intHeight = intHeight + size;
  if (intHeight > 0) {
    gridNm.style.height = intHeight + "px";
  }
};
//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnit = function () {
  scwin.cunit = 1;
  if (lc_unit.getValue() == "02") {
    scwin.cunit = 1000;
  }
  if (lc_unit.getValue() == "03") {
    scwin.cunit = 1000000;
  }
  if (lc_unit.getValue() == "04") {
    scwin.cunit = 100000000;
  }
  scwin.f_changeUnitAmt(scwin.cunit);
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnitAmt = function (unitAmt) {
  if (!ds_master || ds_master.getRowCount() == 0) {
    return;
  }
  const cols = ["yrPlanAmt", "thisPlanAmt", "thisRsltsAmt", "thisVariation", "cumPlanAmt", "cumRsltsAmt", "cumVariation"];
  scwin.ds_master_rcnt = ds_master.getRowCount();
  for (scwin.i = 0; scwin.i < scwin.ds_master_rcnt; scwin.i++) {
    for (scwin.j = 0; scwin.j < cols.length; scwin.j++) {
      if ($c.gus.cfIsNull($p, ds_master.getCellData(scwin.i, cols[scwin.j])) || !$c.num.isNumber($p, ds_master.getCellData(scwin.i, cols[scwin.j]))) {
        ds_master.setCellData(scwin.i, cols[scwin.j], 0);
      } else {
        ds_master.setCellData(scwin.i, cols[scwin.j], $c.num.round($p, $c.num.parseInt($p, ds_master.getCellData(scwin.i, cols[scwin.j])) / unitAmt, 0));
      }
    }
  }
};

